import "./AddRecipe.css"; // reuse same UI
import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate, useParams } from "react-router-dom";
import UserNavbar from "./UserNavbar";

export default function EditRecipe() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [title, setTitle] = useState("");
  const [ingredients, setIngredients] = useState("");
  const [steps, setSteps] = useState("");
  const [cookingTime, setCookingTime] = useState("");
  const [difficulty, setDifficulty] = useState("easy");
  const [image, setImage] = useState(null);

  // 🔹 Load existing recipe
  useEffect(() => {
    const token = localStorage.getItem("token");
    if (!token) {
      navigate("/login");
      return;
    }

    axios
      .get(`http://127.0.0.1:8000/api/recipes/${id}/`, {
        headers: { Authorization: `Token ${token}` },
      })
      .then((res) => {
        setTitle(res.data.title);
        setIngredients(res.data.ingredients);
        setSteps(res.data.steps);
        setCookingTime(res.data.cooking_time);
        setDifficulty(res.data.difficulty);
      })
      .catch(() => alert("Failed to load recipe ❌"));
  }, [id, navigate]);

  // 🔹 Update recipe
  const handleSubmit = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem("token");

    const formData = new FormData();
    formData.append("title", title);
    formData.append("ingredients", ingredients);
    formData.append("steps", steps);
    formData.append("cooking_time", cookingTime);
    formData.append("difficulty", difficulty);
    if (image) formData.append("image", image);

    try {
      await axios.put(
        `http://127.0.0.1:8000/api/recipes/edit/${id}/`,
        formData,
        {
          headers: {
            Authorization: `Token ${token}`,
            "Content-Type": "multipart/form-data",
          },
        }
      );

      alert("Recipe updated successfully ✅");
      navigate("/myrecipe");
    } catch {
      alert("Update failed ❌");
    }
  };

  return (
    <>
      <UserNavbar />

      <div className="add-recipe-page">
        <h2>Edit Recipe</h2>

        <form onSubmit={handleSubmit} className="recipe-form">
          <input value={title} onChange={(e) => setTitle(e.target.value)} />
          <textarea value={ingredients} onChange={(e) => setIngredients(e.target.value)} />
          <textarea value={steps} onChange={(e) => setSteps(e.target.value)} />
          <input value={cookingTime} onChange={(e) => setCookingTime(e.target.value)} />

          <select value={difficulty} onChange={(e) => setDifficulty(e.target.value)}>
            <option value="easy">Easy</option>
            <option value="medium">Medium</option>
            <option value="hard">Hard</option>
          </select>

          <input type="file" onChange={(e) => setImage(e.target.files[0])} />

          <button type="submit">Update Recipe</button>
        </form>
      </div>
    </>
  );
}
